const { content_id } = $input.first().json;

function cfApiPost(urlStr, payload, secret) {
  return new Promise((resolve, reject) => {
    const lib = urlStr.startsWith('https') ? require('https') : require('http');
    const bodyStr = JSON.stringify(payload || {});
    const hdrs = { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(bodyStr), 'x-webhook-secret': secret };
    const req = lib.request(urlStr, { method: 'POST', headers: hdrs }, (res) => {
      let d = ''; res.on('data', c => d += c);
      res.on('end', () => {
        if (res.statusCode >= 400) { reject(new Error('compat HTTP ' + res.statusCode + ': ' + d.slice(0, 200))); return; }
        try { resolve(JSON.parse(d)); } catch (e) { resolve(d); }
      });
    });
    req.on('error', reject);
    req.write(bodyStr); req.end();
  });
}

const apiBase = $env.CF_API_BASE_URL || 'http://cf-api:8000';
const resp = await cfApiPost(`${apiBase}/compat/cf-read-content`, { content_id }, $env.N8N_WEBHOOK_HMAC_SECRET);
return [{ json: resp }];


